	private static void configureSlowQueryThreshold(MemoryStore store, long thresholdSeconds) throws Exception {
		Method method = store.getClass().getMethod("setSlowQueryLogThresholdSeconds", long.class);
		method.invoke(store, thresholdSeconds);
	}

	private static void configureSlowQueryLogFile(MemoryStore store, String logFile) throws Exception {
		Method method = store.getClass().getMethod("setSlowQueryLogFile", String.class);
		method.invoke(store, logFile);
	}

	private static void configureSlowQueryFirstResultThreshold(MemoryStore store, long thresholdSeconds)
			throws Exception {
		Method method = store.getClass().getMethod("setSlowQueryLogFirstResultThresholdSeconds", long.class);
		method.invoke(store, thresholdSeconds);
	}

	private static final class TestMemoryStore extends MemoryStore {
		private final AtomicLong currentTimeMillis = new AtomicLong();
		private final ArrayDeque<Long> queuedTimestamps = new ArrayDeque<>();

		void setCurrentTimeMillis(long value) {
			currentTimeMillis.set(value);
		}

		void queueTimestampMillis(long... values) {
			queuedTimestamps.clear();
			Arrays.stream(values).forEach(queuedTimestamps::addLast);
		}

		protected long getSlowQueryTimestampMillis() {
			if (!queuedTimestamps.isEmpty()) {
				long next = queuedTimestamps.removeFirst();
				currentTimeMillis.set(next);
				return next;
			}
			return currentTimeMillis.get();
		}
	}

	private static final class CapturingAppender extends ListAppender<ILoggingEvent> {
		List<String> messages(Level level) {
			return list.stream()
					.filter(event -> event.getLevel() == level)
					.map(ILoggingEvent::getFormattedMessage)
					.toList();
		}
	}
